mapper.select:
SELECT A.ID, A.ITEM_CD, A.ITEM_NM, A.ITEM_TYPE_CD, A.RATE_TYPE_CD, A.RATE_TYPE_NM, A.SORT_NUM, A.REMARK, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME, A.IS_MAIN_INCOME, A.is_lease, B.DICT_LABEL itemTypeNm FROM m_fee_item A left join M_DICT_DATA B on B.DICT_VALUE=A.ITEM_TYPE_CD AND B.DICT_TYPE='FEE_ITEM_TYPE'
and A.ID = #{id}
and A.ITEM_CD = #{itemCd}
and A.ITEM_NM like #{itemNmLike}
and A.ITEM_TYPE_CD = #{itemTypeCd}
and A.RATE_TYPE_CD = #{rateTypeCd}
and A.SORT_NUM = #{sortNum}
and A.REMARK = #{remark}
order by A.CREATE_TIME desc
